section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/egress-cost-hidden-budget-guide.json",
  "type": "object",
  "required": [
    "report_period",
    "sources",
    "budgets",
    "worst_case_model",
    "nat_gw_alternatives_review",
    "review_date"
  ],
  "properties": {
    "report_period": {
      "type": "string",
      "description": "string"
    },
    "sources": {
      "type": "array",
      "description": "array (each {name, type, monthly_gb, cost_usd, attributed_feature})"
    },
    "budgets": {
      "type": "array",
      "description": "array (each {region, monthly_cap_usd, alert_at_80pct, freeze_at_100pct})"
    },
    "worst_case_model": {
      "type": "object",
      "description": "object (peak_multiplier, projected_gb, projected_cost)"
    },
    "nat_gw_alternatives_review": {
      "type": "array",
      "description": "array (each {nat_gw_id, alternative, est_savings_usd)"
    },
    "review_date": {
      "type": "string",
      "description": "string"
    }
  }
}

example.code:
{
  "report_period": "2026-Q2",
  "sources": [
    {
      "name": "S3 -> internet (downloads)",
      "type": "internet_egress",
      "monthly_gb": 12000,
      "cost_usd": 1080,
      "attributed_feature": "media-downloads"
    },
    {
      "name": "RDS replica -> cross-AZ",
      "type": "cross_az",
      "monthly_gb": 800,
      "cost_usd": 80,
      "attributed_feature": "read-replicas"
    }
  ],
  "budgets": [
    {
      "region": "us-east-1",
      "monthly_cap_usd": 5000,
      "alert_at_80pct": true,
      "freeze_at_100pct": true
    }
  ],
  "worst_case_model": {
    "peak_multiplier": 4,
    "projected_gb": 48000,
    "projected_cost": 4320
  },
  "nat_gw_alternatives_review": [
    {
      "nat_gw_id": "nat-abc",
      "alternative": "VPC endpoint S3",
      "est_savings_usd": 200
    }
  ],
  "review_date": "2026-05-15"
}
